/* prototype.css — demo - 副本 */
/* 完全内联样式，无远程依赖，无全局选择器 */

/* 重置以原型页根容器为作用域 */
.page-wrapper,
.page-wrapper *,
.page-wrapper *::before,
.page-wrapper *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

.page-wrapper {
  width: 100%;
  height: 100vh;
  overflow: hidden;
  position: relative;
  background: #fff;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC", "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
}

/* 可滑动内容区域 */
.scroll-content {
  position: absolute;
  inset: 0;
  overflow-y: auto;
  overflow-x: hidden;
}

/* 隐藏滚动条 */
.scroll-content::-webkit-scrollbar {
  display: none;
  width: 0;
  height: 0;
}
.scroll-content {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

/* 页面容器 */
.page-container {
  width: 1133px;
  min-height: 100vh;
  position: relative;
  margin: 0 auto;
  background: #fff;
}

/* 装饰背景图 */
.deco-bg {
  position: absolute;
  left: 177px;
  top: 20px;
  width: 780px;
  height: 527px;
  object-fit: cover;
}

/* 邀友得奖模块 */
.section-invite {
  position: absolute;
  left: 177px;
  top: 587px;
  width: 780px;
  display: inline-flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 20px;
}

/* 叫叫商城模块 */
