  gap: 20px;
}

/* 模块头部 */
.section-header {
  width: 100%;
  height: 34px;
  padding: 0 4px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-shrink: 0;
}

.section-title {
  color: #666;
  font-size: 22.5px;
  font-weight: 500;
  line-height: 33.75px;
  white-space: nowrap;
  flex-shrink: 0;
}

.section-more {
